  {
    "file": "src/vs/base/common/strings.ts",
    "line": 226,
    "severity": "critical",
    "description": "Case sensitivity flag is inverted. When options.matchCase is true (case-sensitive), the code adds the 'i' flag which means case-INSENSITIVE. This causes all find/replace operations to behave opposite to what's requested - sensitive searches become insensitive and vice versa.",
    "fix_patch": "--- a/src/vs/base/common/strings.ts
+++ b/src/vs/base/common/strings.ts
@@ -223,7 +223,7 @@ export function createRegExp(searchString: string, isRegex: boolean, options: R
 	if (options.global) {
 		modifiers += 'g';
 	}
-	if (options.matchCase) {
+	if (!options.matchCase) {
 		modifiers += 'i';
 	}
 	if (options.multiline) {
"
  },
  {
    "file": "src/vs/editor/common/core/position.ts",
    "line": 103,
    "severity": "critical",
    "description": "The isBefore() method uses <= instead of < for column comparison. The docstring explicitly states 'If the two positions are equal, the result will be false', but <= returns true when columns are equal. This breaks position ordering in selections, cursor movement, and range comparisons.",
    "fix_patch": "--- a/src/vs/editor/common/core/position.ts
+++ b/src/vs/editor/common/core/position.ts
@@ -100,7 +100,7 @@ export class Position {
 		return false;
 	}
 	return a.column < b.column;
 }

 	/**
 	 * Test if this position is before other position.
"
  },
  {
    "file": "src/vs/editor/common/core/range.ts",
    "line": 97,
    "severity": "critical",
    "description": "The containsPosition() method uses >= instead of > for the end boundary check. The docstring states 'If the position is at the edges, will return true' (inclusive), but >= makes the end column exclusive. Positions at the end boundary are incorrectly excluded, breaking selection highlighting, find/replace, and any feature that relies on inclusive range containment.",
    "fix_patch": "--- a/src/vs/editor/common/core/range.ts
+++ b/src/vs/editor/common/core/range.ts
@@ -94,7 +94,7 @@ export class Range {
 		return false;
 	}
 	if (position.lineNumber === range.endLineNumber && position.column > range.endColumn) {
 		return false;
 	}
 	return true;
 }
"
  },
  {
    "file": "src/vs/editor/common/languageFeatureRegistry.ts",
    "line": 195,
    "severity": "critical",
    "description": "The score comparison in _compareByScoreAndTime() is inverted. Lower-scoring providers are sorted first instead of higher-scoring ones. When a._score < b._score, returning -1 puts the lower-scoring provider first. This reverses the entire provider priority system - completions, diagnostics, hover providers, etc. will appear in reverse priority order.",
    "fix_patch": "--- a/src/vs/editor/common/languageFeatureRegistry.ts
+++ b/src/vs/editor/common/languageFeatureRegistry.ts
@@ -192,10 +192,10 @@ export class LanguageFeatureRegistry<T> {
 	}

 	private static _compareByScoreAndTime(a: Entry<any>, b: Entry<any>): number {
-		if (a._score < b._score) {
+		if (a._score > b._score) {
 			return -1;
-		} else if (a._score > b._score) {
+		} else if (a._score < b._score) {
 			return 1;
 		}

 		// De-prioritize built-in providers
"
  },
  {
    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 488,
    "severity": "critical",
    "description": "The isValidMatch() function uses OR (||) instead of AND (&&) for whole-word boundary checking. For whole-word matching, BOTH the left boundary AND the right boundary must be at word boundaries. Using OR makes the function match if either boundary is satisfied, causing partial matches to incorrectly pass as whole-word matches. This breaks the 'Match Whole Word' feature in find/replace.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -487,7 +487,7 @@ function rightIsWordBounday(wordSeparators: WordCharacterClassifier, text: stri
 export function isValidMatch(wordSeparators: WordCharacterClassifier, text: string, textLength: number, matchStartIndex: number, matchLength: number): boolean {
 	return (
 		leftIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
-		|| rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
+		&& rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
 	);
 }
"
  }
]

